--USE <database_name_goes_here>;
USE schema chem_api;

CREATE OR REPLACE TABLE EXAMPLE_STRUCTURE
(
    ID int not null primary key,
    FINGERPRINTS_COMPUTED boolean not null default(false), -- iff true, fingerprints and hashes are in sync with BINARY_MOL
    BINARY_MOL varbinary, 
    PATTERN_FP varbinary,
    MORGAN_FP varbinary,
    EXACT_HASH varchar,
    NO_STEREO_HASH varchar,
    MOLREGNO int, -- We are going to use a sample of small mol structures from the public ChEMBL database
    COMPRESSED_MOLFILE varbinary, -- 'ZSTD' - compressed molfile strings
    SMILES varchar -- frequently used encoding, which makes sense to pre-compute and store
);


